<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">map</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;">i</span><span style="color:#94E2D5;">|</span><span style="color:#89B4FA;font-style:italic;"> format!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Line </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">: some content here&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> i</span><span style="color:#9399B2;">))</span></span>
